import{_ as s,H as n,f as e,i as p}from"./chunks/framework.BHvCMIhP.js";const g=JSON.parse('{"title":"即时通讯","description":"","frontmatter":{},"headers":[],"relativePath":"../systemDesign/18-即时通讯.md","filePath":"../systemDesign/18-即时通讯.md","lastUpdated":1778496697000}'),t={name:"../systemDesign/18-即时通讯.md"};function l(i,a,o,r,c,d){return n(),e("div",null,[...a[0]||(a[0]=[p(`<h1 id="即时通讯" tabindex="-1">即时通讯 <a class="header-anchor" href="#即时通讯" aria-label="Permalink to &quot;即时通讯&quot;">​</a></h1><p>IM(Instant Messaging)是<strong>分布式系统里最难的一类</strong>——同时在线 5 亿人,每一条消息必须可达、有序、不重复、跨设备同步,还要支持万人大群、离线推送、跨地域低延迟。微信工程团队为这个系统投入超过 1000 人年,才把这套东西稳定下来。新手最常见的误解是「IM 就是 WebSocket + Redis 嘛」——<strong>完全不是</strong>。这一篇讲清楚 IM 的核心难点:<strong>长连接管理、消息可达三步 ACK、离线消息存储、群聊扩散、跨设备多端同步</strong>。</p><blockquote><p>一句话先记住:<strong>IM 的核心矛盾是&quot;长连接是有状态的,但有状态难扩展&quot;</strong>——5 亿用户每人一条 TCP,要管理 5 亿个连接;<strong>消息可达靠&quot;业务级三步 ACK&quot;</strong>(send→server→ack→deliver→ack),不是 TCP 层那个 ACK;<strong>群聊不能傻 fanout</strong>——5000 人群一条消息扩散 5000 次,1 万人发同一时间打挂集群。<strong>用 HTTP 做 IM 的人都还在 demo 阶段</strong>,真实 IM 必须长连接。</p></blockquote><hr><h2 id="一、需求拆解" tabindex="-1">一、需求拆解 <a class="header-anchor" href="#一、需求拆解" aria-label="Permalink to &quot;一、需求拆解&quot;">​</a></h2><h3 id="_1-1-功能需求" tabindex="-1">1.1 功能需求 <a class="header-anchor" href="#_1-1-功能需求" aria-label="Permalink to &quot;1.1 功能需求&quot;">​</a></h3><ul><li><strong>单聊</strong>:A 给 B 发消息,B 收到</li><li><strong>群聊</strong>:A 在群里发消息,所有群成员收到</li><li><strong>离线消息</strong>:B 不在线时也能收到 A 发的消息(上线后拉取)</li><li><strong>多端同步</strong>:A 在手机发的消息,同时显示在 PC / Pad</li><li><strong>已读 / 未读</strong></li><li><strong>撤回</strong>(2 分钟内)</li><li><strong>消息类型</strong>:文本 / 图片 / 视频 / 语音 / 文件 / 位置</li></ul><h3 id="_1-2-非功能需求" tabindex="-1">1.2 非功能需求 <a class="header-anchor" href="#_1-2-非功能需求" aria-label="Permalink to &quot;1.2 非功能需求&quot;">​</a></h3><ul><li><strong>可达性</strong>:消息必达(微信级 99.9999%)</li><li><strong>顺序性</strong>:同一会话内消息严格有序</li><li><strong>延迟</strong>:同地域 &lt; 100ms,跨地域 &lt; 500ms</li><li><strong>同时在线</strong>:5 亿</li><li><strong>峰值消息</strong>:春节红包高峰 100 万条/秒</li></ul><h3 id="_1-3-这一轮不做" tabindex="-1">1.3 这一轮不做 <a class="header-anchor" href="#_1-3-这一轮不做" aria-label="Permalink to &quot;1.3 这一轮不做&quot;">​</a></h3><ul><li>音视频通话(WebRTC,详见 mediaTech 系列)</li><li>端到端加密(信号协议 / Signal Protocol)</li><li>内容审核</li></ul><hr><h2 id="二、容量估算" tabindex="-1">二、容量估算 <a class="header-anchor" href="#二、容量估算" aria-label="Permalink to &quot;二、容量估算&quot;">​</a></h2><h3 id="_2-1-长连接数" tabindex="-1">2.1 长连接数 <a class="header-anchor" href="#_2-1-长连接数" aria-label="Permalink to &quot;2.1 长连接数&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DAU 10 亿,同时在线峰值 = DAU × 30% = 3 亿同时在线</span></span>
<span class="line"><span>单台 IM 网关 ≈ 10 万长连接(epoll 调优后)</span></span>
<span class="line"><span>→ 至少 3000 台 IM 网关</span></span></code></pre></div><h3 id="_2-2-消息-qps" tabindex="-1">2.2 消息 QPS <a class="header-anchor" href="#_2-2-消息-qps" aria-label="Permalink to &quot;2.2 消息 QPS&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DAU × 人均发消息 50 条 / 天 = 500 亿条 / 天</span></span>
<span class="line"><span>平均 QPS = 50 万,峰值 ≈ 500 万</span></span>
<span class="line"><span></span></span>
<span class="line"><span>群聊放大:平均一条消息发给 10 个人(单聊 1 + 群聊放大)</span></span>
<span class="line"><span>→ 实际投递 = 500 万 × 10 = 5000 万投递 QPS</span></span></code></pre></div><h3 id="_2-3-存储" tabindex="-1">2.3 存储 <a class="header-anchor" href="#_2-3-存储" aria-label="Permalink to &quot;2.3 存储&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>500 亿消息 / 天 × 500 字节 = 25 TB / 天</span></span>
<span class="line"><span>保留 5 年 = 45 PB</span></span>
<span class="line"><span>→ 必须分层存储(热 + 冷)</span></span></code></pre></div><h3 id="_2-4-关键洞察" tabindex="-1">2.4 关键洞察 <a class="header-anchor" href="#_2-4-关键洞察" aria-label="Permalink to &quot;2.4 关键洞察&quot;">​</a></h3><p><strong>IM 是少数几个&quot;读不是瓶颈、写才是&quot;的系统</strong>——每个用户读自己的消息很轻,但<strong>消息扩散写</strong>才是大头。</p><hr><h2 id="三、为什么-im-必须用长连接" tabindex="-1">三、为什么 IM 必须用长连接 <a class="header-anchor" href="#三、为什么-im-必须用长连接" aria-label="Permalink to &quot;三、为什么 IM 必须用长连接&quot;">​</a></h2><h3 id="_3-1-http-短连接的问题" tabindex="-1">3.1 HTTP 短连接的问题 <a class="header-anchor" href="#_3-1-http-短连接的问题" aria-label="Permalink to &quot;3.1 HTTP 短连接的问题&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>HTTP 收消息 = 客户端轮询服务器 (&quot;有新消息吗?&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每秒一次 → 5 亿用户每秒 5 亿请求 → 永远没人扛得住</span></span>
<span class="line"><span>每分钟一次 → 消息延迟 1 分钟,用户体验崩溃</span></span></code></pre></div><h3 id="_3-2-长连接-websocket-自研协议" tabindex="-1">3.2 长连接(WebSocket / 自研协议) <a class="header-anchor" href="#_3-2-长连接-websocket-自研协议" aria-label="Permalink to &quot;3.2 长连接(WebSocket / 自研协议)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端连一次 → TCP 长连接保持 → 服务端有消息主动 push</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5 亿用户 = 5 亿条 TCP 连接(成本可控)</span></span>
<span class="line"><span>延迟 &lt; 100ms(TCP 往返一次)</span></span></code></pre></div><p><strong>主流选择</strong>:</p><table tabindex="0"><thead><tr><th>协议</th><th>适合</th></tr></thead><tbody><tr><td>WebSocket</td><td>Web 端首选</td></tr><tr><td>MQTT</td><td>IoT / 移动端低功耗</td></tr><tr><td>自研 TCP / TLS</td><td>微信、QQ 都自研(协议头更紧凑)</td></tr></tbody></table><blockquote><p>微信用自研协议(基于 TCP),<strong>协议头比 HTTP 小一个量级</strong>,移动端省流量、省电。</p></blockquote><hr><h2 id="四、长连接架构" tabindex="-1">四、长连接架构 <a class="header-anchor" href="#四、长连接架构" aria-label="Permalink to &quot;四、长连接架构&quot;">​</a></h2><h3 id="_4-1-核心组件" tabindex="-1">4.1 核心组件 <a class="header-anchor" href="#_4-1-核心组件" aria-label="Permalink to &quot;4.1 核心组件&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                   用户 (手机/PC)</span></span>
<span class="line"><span>                       ↓ TCP 长连接</span></span>
<span class="line"><span>                   ┌───────────┐</span></span>
<span class="line"><span>                   │  接入层 LB │  (TCP 层,L4)</span></span>
<span class="line"><span>                   └─────┬─────┘</span></span>
<span class="line"><span>                         ↓</span></span>
<span class="line"><span>              ┌──────────┴──────────┐</span></span>
<span class="line"><span>              ↓                     ↓</span></span>
<span class="line"><span>     ┌──────────────┐       ┌──────────────┐</span></span>
<span class="line"><span>     │  IM Gateway  │  ...  │  IM Gateway  │  3000+ 台</span></span>
<span class="line"><span>     │  (长连接持有) │       │              │</span></span>
<span class="line"><span>     └──────┬───────┘       └──────┬───────┘</span></span>
<span class="line"><span>            ↓                       ↓</span></span>
<span class="line"><span>       ┌────┴───────────────────────┴────┐</span></span>
<span class="line"><span>       │     消息处理服务(无状态)         │</span></span>
<span class="line"><span>       └────┬────────────────────────────┘</span></span>
<span class="line"><span>            ↓</span></span>
<span class="line"><span>       ┌────┴────────┐</span></span>
<span class="line"><span>       │   Kafka     │  (消息队列,核心数据通道)</span></span>
<span class="line"><span>       └────┬────────┘</span></span>
<span class="line"><span>            ↓</span></span>
<span class="line"><span>       ┌────┴───────────────┬─────────────────┐</span></span>
<span class="line"><span>       ↓                    ↓                 ↓</span></span>
<span class="line"><span>   ┌────────┐         ┌──────────┐      ┌──────────┐</span></span>
<span class="line"><span>   │ 消息存储 │         │ 路由服务 │      │ 推送服务 │</span></span>
<span class="line"><span>   │ (HBase) │         │  (谁在哪)│      │ (离线)   │</span></span>
<span class="line"><span>   └────────┘         └──────────┘      └──────────┘</span></span></code></pre></div><h3 id="_4-2-关键-用户-→-im-gateway-的路由" tabindex="-1">4.2 关键:用户 → IM Gateway 的路由 <a class="header-anchor" href="#_4-2-关键-用户-→-im-gateway-的路由" aria-label="Permalink to &quot;4.2 关键:用户 → IM Gateway 的路由&quot;">​</a></h3><p><strong>问题</strong>:A 给 B 发消息,<strong>B 连在哪台 Gateway 上</strong>?</p><p><strong>解法:全局路由表</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>key:   user_route:{user_id}</span></span>
<span class="line"><span>value: gateway_id (B 当前连接的 Gateway)</span></span>
<span class="line"><span>存储:  Redis Cluster</span></span></code></pre></div><p><strong>用户上线时</strong>:Gateway 把&quot;user_id → gateway_id&quot;写入 Redis。 <strong>用户下线时</strong>:Gateway 把这个 key 删除。 <strong>发消息时</strong>:查 Redis 找到 B 的 Gateway,把消息推送过去。</p><h3 id="_4-3-一致性哈希优化路由" tabindex="-1">4.3 一致性哈希优化路由 <a class="header-anchor" href="#_4-3-一致性哈希优化路由" aria-label="Permalink to &quot;4.3 一致性哈希优化路由&quot;">​</a></h3><p>为了让长连接尽量稳定,<strong>用户 ID 一致性哈希到 Gateway</strong>:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gateway </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> consistent_hash.get_node(user_id)</span></span></code></pre></div><p>详见 13 篇一致性哈希。<strong>优势:扩缩容时只影响 1/N 用户重连</strong>。</p><hr><h2 id="五、消息可达-三步-ack" tabindex="-1">五、消息可达:三步 ACK <a class="header-anchor" href="#五、消息可达-三步-ack" aria-label="Permalink to &quot;五、消息可达:三步 ACK&quot;">​</a></h2><p><strong>TCP 的 ACK 不能保证业务可达</strong>——TCP 收到了不等于应用处理了。</p><h3 id="_5-1-完整三步流程" tabindex="-1">5.1 完整三步流程 <a class="header-anchor" href="#_5-1-完整三步流程" aria-label="Permalink to &quot;5.1 完整三步流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A 发消息 → 服务器</span></span>
<span class="line"><span>  ↓ ACK1(服务器收到了,赋予 server_msg_id)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>服务器 → B(在线)</span></span>
<span class="line"><span>  ↓ ACK2(B 收到了)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>B 客户端处理(写入本地数据库)</span></span>
<span class="line"><span>  ↓ ACK3(业务确认)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>服务器收到 ACK3 → 标记消息为&quot;已投递&quot;</span></span></code></pre></div><h3 id="_5-2-失败重试" tabindex="-1">5.2 失败重试 <a class="header-anchor" href="#_5-2-失败重试" aria-label="Permalink to &quot;5.2 失败重试&quot;">​</a></h3><p><strong>任何一个 ACK 没回来 → 重试</strong>:</p><ul><li>A 没收 ACK1 → A 重发(同 client_msg_id,服务器幂等)</li><li>B 没收消息 / 服务器没收 ACK2 → 服务器重推</li><li>服务器没收 ACK3 → B 标记为已读时再 ACK</li></ul><p><strong>幂等关键</strong>:消息有 <code>client_msg_id</code>(A 生成的客户端 ID),服务器去重时用它。</p><h3 id="_5-3-消息状态机" tabindex="-1">5.3 消息状态机 <a class="header-anchor" href="#_5-3-消息状态机" aria-label="Permalink to &quot;5.3 消息状态机&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>created → server_received → delivered → read</span></span></code></pre></div><p>每个状态用户都能看到(已发送 / 已送达 / 已读)。</p><hr><h2 id="六、消息存储-写扩散-vs-读扩散" tabindex="-1">六、消息存储:写扩散 vs 读扩散 <a class="header-anchor" href="#六、消息存储-写扩散-vs-读扩散" aria-label="Permalink to &quot;六、消息存储:写扩散 vs 读扩散&quot;">​</a></h2><p>最核心的设计抉择,<strong>和 16 篇 Twitter 的 Push/Pull 类似</strong>:</p><h3 id="_6-1-写扩散-push-主流" tabindex="-1">6.1 写扩散(Push,主流) <a class="header-anchor" href="#_6-1-写扩散-push-主流" aria-label="Permalink to &quot;6.1 写扩散(Push,主流)&quot;">​</a></h3><p>发消息时,<strong>为每个收件人写一条</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A 发给 B:</span></span>
<span class="line"><span>  inbox:A 写一份(发件箱)</span></span>
<span class="line"><span>  inbox:B 写一份(收件箱)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>群聊 1000 人:</span></span>
<span class="line"><span>  inbox 写 1000 份</span></span></code></pre></div><p><strong>优点</strong>:读极快(直接读自己的 inbox)。 <strong>缺点</strong>:大群放大写入。</p><h3 id="_6-2-读扩散-pull-小群和小型-im" tabindex="-1">6.2 读扩散(Pull,小群和小型 IM) <a class="header-anchor" href="#_6-2-读扩散-pull-小群和小型-im" aria-label="Permalink to &quot;6.2 读扩散(Pull,小群和小型 IM)&quot;">​</a></h3><p>发消息只写一份到群,<strong>读时聚合</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A 在群发:</span></span>
<span class="line"><span>  group_messages:{group_id} 写一份</span></span>
<span class="line"><span></span></span>
<span class="line"><span>B 读群:</span></span>
<span class="line"><span>  按 group_id + last_read_id 查最新消息</span></span></code></pre></div><p><strong>优点</strong>:写少,适合大群。 <strong>缺点</strong>:消息按会话存,跨会话聚合&quot;我所有未读&quot;需要遍历所有群。</p><h3 id="_6-3-微信用什么" tabindex="-1">6.3 微信用什么 <a class="header-anchor" href="#_6-3-微信用什么" aria-label="Permalink to &quot;6.3 微信用什么&quot;">​</a></h3><p><strong>微信用写扩散</strong>——99% 是单聊或小群,写扩散读快;<strong>大群另开优化路径</strong>(下文 §8)。</p><h3 id="_6-4-存储引擎" tabindex="-1">6.4 存储引擎 <a class="header-anchor" href="#_6-4-存储引擎" aria-label="Permalink to &quot;6.4 存储引擎&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>活跃 30 天消息:    HBase / Cassandra(海量写入,LSM 树)</span></span>
<span class="line"><span>30 天前归档:       对象存储(S3 / OSS),按用户 ID 分目录</span></span></code></pre></div><p><strong>HBase 的优势</strong>:</p><ul><li>写入 LSM,扛海量写</li><li>按 user_id + timestamp 范围扫描快(读 inbox)</li><li>单 region 数据量大时自动分裂</li></ul><hr><h2 id="七、离线消息" tabindex="-1">七、离线消息 <a class="header-anchor" href="#七、离线消息" aria-label="Permalink to &quot;七、离线消息&quot;">​</a></h2><p>B 不在线时,<strong>消息暂存</strong>——B 上线后拉取。</p><h3 id="_7-1-离线消息存储" tabindex="-1">7.1 离线消息存储 <a class="header-anchor" href="#_7-1-离线消息存储" aria-label="Permalink to &quot;7.1 离线消息存储&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>key: offline:{user_id}</span></span>
<span class="line"><span>type: List(消息 ID 列表)</span></span>
<span class="line"><span>TTL: 7 天(超过的认为永远不在线了)</span></span></code></pre></div><p>或直接存到 inbox(写扩散),<strong>上线时按 last_sync_id 拉新消息</strong>。</p><h3 id="_7-2-离线推送" tabindex="-1">7.2 离线推送 <a class="header-anchor" href="#_7-2-离线推送" aria-label="Permalink to &quot;7.2 离线推送&quot;">​</a></h3><p>B 长时间不在线 → 通过手机推送(APNs / 小米推送 / 华为推送):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;你有 1 条新消息&quot; → 用户点击进入 App → 触发拉取离线消息</span></span></code></pre></div><p><strong>关键</strong>:不直接推消息内容(隐私 + 推送 payload 大小限制),只推一个通知。</p><h3 id="_7-3-离线消息的限制" tabindex="-1">7.3 离线消息的限制 <a class="header-anchor" href="#_7-3-离线消息的限制" aria-label="Permalink to &quot;7.3 离线消息的限制&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>保留 7 天   超过删除(占用大量存储)</span></span>
<span class="line"><span>最多 1000 条 太多了挤占,只显示最近 1000 条</span></span>
<span class="line"><span>大文件不存  视频 / 图片只存 URL,真内容在对象存储</span></span></code></pre></div><hr><h2 id="八、群聊优化-大群-读扩散" tabindex="-1">八、群聊优化:大群&quot;读扩散&quot; <a class="header-anchor" href="#八、群聊优化-大群-读扩散" aria-label="Permalink to &quot;八、群聊优化:大群&quot;读扩散&quot;&quot;">​</a></h2><p>写扩散在大群里崩溃:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>微信 500 人群,一个人发一条消息 → 写 500 份</span></span>
<span class="line"><span>微信 1 万人群(企业群),一条消息 → 写 1 万份</span></span>
<span class="line"><span></span></span>
<span class="line"><span>10 万个群同时发消息 → 10 万 × 1 万 = 10 亿次写入/秒 → 不可能</span></span></code></pre></div><h3 id="_8-1-大群用读扩散" tabindex="-1">8.1 大群用读扩散 <a class="header-anchor" href="#_8-1-大群用读扩散" aria-label="Permalink to &quot;8.1 大群用读扩散&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>群消息只写一份:group_messages:{group_id}</span></span>
<span class="line"><span>每个用户记录:last_read:{user_id}:{group_id}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>用户进群:从 last_read 拉最新消息</span></span>
<span class="line"><span>未读计数:总数 - last_read</span></span></code></pre></div><p><strong>节省 1000 倍写入</strong>——但读群消息时多一步聚合。</p><h3 id="_8-2-群聊还是要-通知" tabindex="-1">8.2 群聊还是要&quot;通知&quot; <a class="header-anchor" href="#_8-2-群聊还是要-通知" aria-label="Permalink to &quot;8.2 群聊还是要&quot;通知&quot;&quot;">​</a></h3><p>读扩散省了存储,<strong>但用户怎么知道有新消息</strong>?</p><p><strong>轻量通知</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>群里有人发消息 → 推送一条&quot;通知&quot;给所有在线成员</span></span>
<span class="line"><span>通知 payload 极小:{group_id, latest_msg_id, sender_id}</span></span>
<span class="line"><span>不带消息内容,客户端按通知去拉</span></span></code></pre></div><p><strong>离线成员</strong>:不通知 / 仅推送一次(避免红点轰炸)。</p><h3 id="_8-3-万人群的边界" tabindex="-1">8.3 万人群的边界 <a class="header-anchor" href="#_8-3-万人群的边界" aria-label="Permalink to &quot;8.3 万人群的边界&quot;">​</a></h3><p>微信 500 人,QQ 群 2000 人,企业微信 1 万人——<strong>超过这个就算&quot;频道&quot;了</strong>(类似 Discord),用专门的频道架构(订阅模式,消息只存一份,订阅者按需拉)。</p><hr><h2 id="九、多端同步" tabindex="-1">九、多端同步 <a class="header-anchor" href="#九、多端同步" aria-label="Permalink to &quot;九、多端同步&quot;">​</a></h2><p>A 同时在手机 + PC 登录,<strong>消息要在两端都显示</strong>。</p><h3 id="_9-1-多端的会话状态" tabindex="-1">9.1 多端的会话状态 <a class="header-anchor" href="#_9-1-多端的会话状态" aria-label="Permalink to &quot;9.1 多端的会话状态&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>key: user_devices:{user_id}</span></span>
<span class="line"><span>value: [device_1_gateway, device_2_gateway, ...]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>发消息时:推送到所有设备的 Gateway</span></span></code></pre></div><h3 id="_9-2-已读同步" tabindex="-1">9.2 已读同步 <a class="header-anchor" href="#_9-2-已读同步" aria-label="Permalink to &quot;9.2 已读同步&quot;">​</a></h3><p>A 在手机上读了消息 → PC 上的红点也要清:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A 在手机上 read msg_123 → 服务器记 read_state:{user}:{conv} = 123</span></span>
<span class="line"><span>广播到所有设备:你的会话 X 已读到 msg_123</span></span></code></pre></div><h3 id="_9-3-漫游消息" tabindex="-1">9.3 漫游消息 <a class="header-anchor" href="#_9-3-漫游消息" aria-label="Permalink to &quot;9.3 漫游消息&quot;">​</a></h3><p>新设备登录 → 拉取<strong>最近 N 天</strong>的消息:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>新 PC 登录 → 服务器返回最近 7 天消息(从云端 HBase 拉)</span></span>
<span class="line"><span>本地数据库填充 → 用户看到完整历史</span></span></code></pre></div><blockquote><p><strong>微信&quot;换手机后聊天记录在哪&quot;</strong> —— 需要服务端有「漫游消息」服务,<strong>这是一个独立的子系统</strong>。</p></blockquote><hr><h2 id="十、消息顺序" tabindex="-1">十、消息顺序 <a class="header-anchor" href="#十、消息顺序" aria-label="Permalink to &quot;十、消息顺序&quot;">​</a></h2><p>「同一会话内消息严格有序」——<strong>怎么保证</strong>?</p><h3 id="_10-1-单聊顺序" tabindex="-1">10.1 单聊顺序 <a class="header-anchor" href="#_10-1-单聊顺序" aria-label="Permalink to &quot;10.1 单聊顺序&quot;">​</a></h3><p>A 给 B 连发 3 条 → B 必须按顺序看到。</p><p><strong>问题</strong>:网络抖动,2 号到了,1 号还在路上 → B 先看到 2 号。</p><p><strong>解决</strong>:</p><ul><li>A 客户端给消息打<strong>单调递增的本地序号</strong></li><li>B 客户端按本地序号缓冲,顺序展示</li></ul><h3 id="_10-2-群聊顺序" tabindex="-1">10.2 群聊顺序 <a class="header-anchor" href="#_10-2-群聊顺序" aria-label="Permalink to &quot;10.2 群聊顺序&quot;">​</a></h3><p>群里 3 个人同时发消息 → <strong>服务器统一定序</strong>:</p><ul><li>服务器收到第一条赋 group_seq=1</li><li>第二条 group_seq=2</li><li>客户端按 group_seq 排列</li></ul><p><strong>关键:群消息必须由同一个 partition / 同一个服务实例处理</strong>——按 group_id 哈希到固定 partition,保证顺序。<strong>详见 10 篇 MQ 顺序消息</strong>。</p><hr><h2 id="十一、关键问题-撤回-删除-编辑" tabindex="-1">十一、关键问题:撤回 / 删除 / 编辑 <a class="header-anchor" href="#十一、关键问题-撤回-删除-编辑" aria-label="Permalink to &quot;十一、关键问题:撤回 / 删除 / 编辑&quot;">​</a></h2><p>发出去的消息要撤回:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A 发消息 msg_123 → B 已经收到并显示</span></span>
<span class="line"><span>A 撤回 → 服务器记 msg_123 状态为 recalled</span></span>
<span class="line"><span>       → 推送 &quot;撤回&quot; 信号到所有设备</span></span>
<span class="line"><span>       → B 客户端收到后,删除本地的 msg_123,显示 &quot;A 撤回了一条消息&quot;</span></span></code></pre></div><p><strong>已经离线的人怎么办</strong>:撤回信号也通过同样的可达机制(三步 ACK)送达。</p><p><strong>2 分钟限制</strong>:服务端校验 <code>now - msg.created_at &lt; 120s</code>,超过拒绝撤回。</p><hr><h2 id="十二、跨地域多机房" tabindex="-1">十二、跨地域多机房 <a class="header-anchor" href="#十二、跨地域多机房" aria-label="Permalink to &quot;十二、跨地域多机房&quot;">​</a></h2><p>微信 / WhatsApp 全球用户:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>中美用户互发消息 → 跨太平洋光纤 → 200ms+ 延迟</span></span>
<span class="line"><span>                ↓</span></span>
<span class="line"><span>                 用户体验差</span></span></code></pre></div><p><strong>优化</strong>:</p><ul><li>用户就近接入本地机房</li><li>消息存储跨机房异步复制</li><li>关键 metadata(用户路由表)全球同步</li></ul><p>详见 25 篇异地多活。</p><hr><h2 id="十三、最终架构图" tabindex="-1">十三、最终架构图 <a class="header-anchor" href="#十三、最终架构图" aria-label="Permalink to &quot;十三、最终架构图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                     用户 (手机/PC)</span></span>
<span class="line"><span>                          ↓ 长连接</span></span>
<span class="line"><span>                     Anycast LB</span></span>
<span class="line"><span>                          ↓</span></span>
<span class="line"><span>     ┌─── IM Gateway 集群(3000 台,无状态) ────┐</span></span>
<span class="line"><span>     │   每台维护 10 万 TCP 连接                │</span></span>
<span class="line"><span>     └────────────┬───────────────────────────┘</span></span>
<span class="line"><span>                  ↓</span></span>
<span class="line"><span>            ┌─────┴─────┐</span></span>
<span class="line"><span>            ↓           ↓</span></span>
<span class="line"><span>       消息处理      路由服务</span></span>
<span class="line"><span>       (无状态)    (Redis 路由表)</span></span>
<span class="line"><span>            ↓</span></span>
<span class="line"><span>         Kafka(消息总线)</span></span>
<span class="line"><span>            ↓</span></span>
<span class="line"><span>   ┌────────┼────────┬─────────┐</span></span>
<span class="line"><span>   ↓        ↓        ↓         ↓</span></span>
<span class="line"><span> HBase   离线推送  写扩散     反作弊</span></span>
<span class="line"><span> (消息)   (APNs)   Worker    审核</span></span>
<span class="line"><span>                     ↓</span></span>
<span class="line"><span>              用户 inbox 写入</span></span></code></pre></div><hr><h2 id="十四、踩坑提醒" tabindex="-1">十四、踩坑提醒 <a class="header-anchor" href="#十四、踩坑提醒" aria-label="Permalink to &quot;十四、踩坑提醒&quot;">​</a></h2><ol><li><strong>用 HTTP 短连接做 IM</strong>——只能 demo,生产必须长连接</li><li><strong>长连接没心跳</strong>——TCP 半死状态(连接还在但服务不响应),客户端永远收不到消息</li><li><strong>没用 Anycast / 就近接入</strong>——跨地域用户延迟 500ms+</li><li><strong>大群用写扩散</strong>——一条消息扩散 1 万份,集群崩</li><li><strong>不做消息幂等</strong>——网络重试导致消息重复</li><li><strong>只信 TCP ACK</strong>——TCP 收到 ≠ 业务收到,必须三步业务 ACK</li><li><strong>没有离线消息保留期</strong>——存所有历史消息成本爆炸</li><li><strong>多端同步靠每端单独连</strong>——消息推 N 次重复</li><li><strong>单聊和群聊用同一存储模型</strong>——没法 hybrid 优化</li><li><strong>没限流大群</strong>——某个万人群活跃时打挂集群</li><li><strong>撤回信号没 ACK</strong>——下线用户上线后看到本该撤回的消息</li><li><strong>路由表不持久化</strong>——Gateway 重启所有用户掉线,要全部重连</li></ol><hr><p>下一篇:<code>19-视频点播.md</code>,讲 YouTube / B 站级别的视频系统——<strong>为什么视频点播 = 95% 的 CDN + 5% 的源站</strong>,转码流水线、自适应码率(HLS / DASH),如何在 1080p 和 4K 之间根据用户网络动态切换,以及为什么视频网站的真正成本是带宽不是计算。</p>`,143)])])}const u=s(t,[["render",l]]);export{g as __pageData,u as default};
